contracts/NexusVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

/**
 * NexusVault — On-chain dead-man switch inheritance vault.
 *
 * Rules:
 * - Owner pings to reset the inactivity clock.
 * - If block.timestamp > lastPing + inactivityPeriod AND executed == false,
 *   anyone can call executeInheritance().
 * - The vault balance is split equally among all beneficiaries.
 * - ETH only originally; extended to support ERC20 with percentage splits.
 * - Automation-compatible via checkUpkeep / performUpkeep.
 * - Owner can optionally store a Fileverse CID for a will document.
 */
contract NexusVault is ReentrancyGuard {
    using SafeERC20 for IERC20;
    address public owner;
    address[] public beneficiaries;
    uint256[] public shares; // basis points per beneficiary, must sum to 10000
    uint256 public lastPing;
    uint256 public inactivityPeriod;
    bool public executed;
    string public willDocumentHash; // optional Fileverse CID

    uint256 public constant FEE_BPS = 100; // 1% protocol fee
    address public feeRecipient; // receives protocol fee
    address[] public tokenWhitelist; // approved ERC20 tokens

    event Pinged(address indexed owner, uint256 timestamp);
    event InheritanceExecuted(address[] beneficiaries, uint256 sharePerBeneficiary);
    event WillDocumentSet(string cid);
    event FundsReceived(address indexed sender, uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    constructor(
        address _owner,
        address[] memory _beneficiaries,
        uint256[] memory _shares,
        uint256 _inactivityPeriod,
        address _feeRecipient
    ) {
        require(_beneficiaries.length > 0, "No beneficiaries");
        require(_inactivityPeriod > 0, "Invalid inactivity period");
        require(_beneficiaries.length == _shares.length, "length mismatch");
        require(_feeRecipient != address(0), "Invalid fee recipient");

        uint256 total;
        for (uint256 i = 0; i < _shares.length; i++) {
            total += _shares[i];
        }
        require(total == 10_000, "shares must sum to 10000");

        owner = _owner;
        beneficiaries = _beneficiaries;
        shares = _shares;
        inactivityPeriod = _inactivityPeriod;
        lastPing = block.timestamp;
        executed = false;
        feeRecipient = _feeRecipient;
    }

    receive() external payable {
        emit FundsReceived(msg.sender, msg.value);
    }

    /**
     * Owner calls this to reset the inactivity clock.
     */
    function ping() external onlyOwner {
        require(!executed, "Already executed");
        lastPing = block.timestamp;
        emit Pinged(msg.sender, block.timestamp);
    }

    /**
     * Execute inheritance: transfers equal share to each beneficiary.
     * Can be called by anyone once inactivity condition is met.
     */
    function executeInheritance() public nonReentrant {
        require(!executed, "Already executed");
        require(
            block.timestamp > lastPing + inactivityPeriod,
            "Inactivity period not elapsed"
        );
        require(address(this).balance > 0, "No ETH to distribute");
        require(beneficiaries.length > 0, "No beneficiaries");
        require(beneficiaries.length == shares.length, "shares length mismatch");

        executed = true;

        uint256 total = address(this).balance;
        uint256 fee = (total * FEE_BPS) / 10_000;
        payable(feeRecipient).transfer(fee);

        uint256 remaining = address(this).balance;
        uint256 distributed;

        for (uint256 i = 0; i < beneficiaries.length; i++) {
            uint256 shareAmount;
            if (i == beneficiaries.length - 1) {
                // last heir receives any dust
                shareAmount = remaining - distributed;
            } else {
                shareAmount = (remaining * shares[i]) / 10_000;
            }
            distributed += shareAmount;
            payable(beneficiaries[i]).transfer(shareAmount);
        }

        emit InheritanceExecuted(beneficiaries, distributed / beneficiaries.length);
    }

    /**
     * Chainlink Automation compatible — check if upkeep is needed.
     * Returns true when: inactivity elapsed AND not yet executed AND has balance.
     */
    function checkUpkeep(bytes calldata)
        external
        view
        returns (bool upkeepNeeded, bytes memory)
    {
        upkeepNeeded =
            !executed &&
            block.timestamp > lastPing + inactivityPeriod &&
            address(this).balance > 0;
        return (upkeepNeeded, "");
    }

    /**
     * Chainlink Automation compatible — perform the upkeep.
     */
    function performUpkeep(bytes calldata) external {
        executeInheritance();
    }

    /**
     * Distribute ERC20 balances after ETH inheritance has executed.
     * Requires token to be whitelisted. Uses same shares[] percentages.
     */
    function claimERC20(address token) external nonReentrant {
        require(executed, "Not yet executed");
        require(isWhitelisted(token), "Token not approved");

        IERC20 t = IERC20(token);
        uint256 bal = t.balanceOf(address(this));
        require(bal > 0, "No token balance");

        uint256 fee = (bal * FEE_BPS) / 10_000;
        t.safeTransfer(feeRecipient, fee);

        uint256 remaining = t.balanceOf(address(this));
        require(beneficiaries.length == shares.length, "shares length mismatch");

        uint256 distributed;
        for (uint256 i = 0; i < beneficiaries.length; i++) {
            uint256 shareAmount;
            if (i == beneficiaries.length - 1) {
                shareAmount = remaining - distributed;
            } else {
                shareAmount = (remaining * shares[i]) / 10_000;
            }
            distributed += shareAmount;
            t.safeTransfer(beneficiaries[i], shareAmount);
        }
    }

    /**
     * Owner can store a Fileverse CID for the will document.
     * Only the hash/CID is stored — no file content on-chain.
     */
    function setWillDocumentHash(string memory cid) external onlyOwner {
        willDocumentHash = cid;
        emit WillDocumentSet(cid);
    }

    /**
     * Owner can update beneficiaries and their percentage splits before execution.
     * Shares are expressed in basis points (total must equal 10000).
     */
    function updateBeneficiaries(
        address[] calldata _beneficiaries,
        uint256[] calldata _shares
    ) external onlyOwner {
        require(!executed, "Already executed");
        require(_beneficiaries.length > 0, "No beneficiaries");
        require(_beneficiaries.length == _shares.length, "length mismatch");

        uint256 total;
        for (uint256 i = 0; i < _shares.length; i++) {
            total += _shares[i];
        }
        require(total == 10_000, "shares must sum to 10000");

        beneficiaries = _beneficiaries;
        shares = _shares;
    }

    /**
     * Owner can cancel the vault before execution and reclaim all ETH.
     */
    function cancelVault() external onlyOwner nonReentrant {
        require(!executed, "Already executed");
        executed = true;
        payable(owner).transfer(address(this).balance);
    }

    /**
     * Owner-controlled ERC20 whitelist management.
     */
    function setTokenWhitelist(address[] calldata tokens) external onlyOwner {
        tokenWhitelist = tokens;
    }

    function isWhitelisted(address token) public view returns (bool) {
        for (uint256 i = 0; i < tokenWhitelist.length; i++) {
            if (tokenWhitelist[i] == token) {
                return true;
            }
        }
        return false;
    }

    // View helpers

    function getBeneficiaries() external view returns (address[] memory) {
        return beneficiaries;
    }

    function getTimeRemaining() external view returns (uint256) {
        uint256 expiry = lastPing + inactivityPeriod;
        if (block.timestamp >= expiry) return 0;
        return expiry - block.timestamp;
    }

    function getBalance() external view returns (uint256) {
        return address(this).balance;
    }
}

contracts/VaultFactory.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./NexusVault.sol";

/**
 * VaultFactory — Deploys NexusVault instances.
 *
 * Rules:
 * - One vault per user address (enforced on-chain).
 * - Maps owner address → vault address.
 * - Emits VaultCreated on each deployment.
 */
contract VaultFactory {
    mapping(address => address) public vaults;

    address public feeRecipient;

    event VaultCreated(
        address indexed owner,
        address indexed vaultAddress,
        uint256 inactivityPeriod
    );

    constructor(address _feeRecipient) {
        require(_feeRecipient != address(0), "Invalid fee recipient");
        feeRecipient = _feeRecipient;
    }

    /**
     * Deploy a new NexusVault for the caller.
     * @param beneficiaries     Array of beneficiary addresses (no duplicates, no zero address).
     * @param shares            Basis points per beneficiary, must sum to 10000.
     * @param inactivityPeriod  Seconds of inactivity before inheritance executes.
     */
    function createVault(
        address[] calldata beneficiaries,
        uint256[] calldata shares,
        uint256 inactivityPeriod
    ) external returns (address) {
        require(vaults[msg.sender] == address(0), "Vault already exists");
        require(beneficiaries.length > 0, "No beneficiaries");
        require(beneficiaries.length == shares.length, "length mismatch");
        require(inactivityPeriod >= 1 days, "Min inactivity is 1 day");

        for (uint256 i = 0; i < beneficiaries.length; i++) {
            require(beneficiaries[i] != address(0), "Zero address not allowed");
        }

        NexusVault vault = new NexusVault(
            msg.sender,
            beneficiaries,
            shares,
            inactivityPeriod,
            feeRecipient
        );

        vaults[msg.sender] = address(vault);

        emit VaultCreated(msg.sender, address(vault), inactivityPeriod);

        return address(vault);
    }

    function getVault(address owner) external view returns (address) {
        return vaults[owner];
    }
}

contracts/WillRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/// Minimal interface to trigger NexusVault execution.
interface INexusVault {
    function executeInheritance() external;
}

/**
 * WillRegistry — Off-chain friendly registry for NexusVault wills.
 *
 * - One will per owner address.
 * - Stores beneficiary, linked vault, and Fileverse IPFS CID.
 * - Tracks a simple trust tree with level-1 trustees and backups.
 * - Supports ZK verification + approvals from trustees.
 * - Emits events that the backend indexes and uses for notifications.
 *
 * NOTE: This is intentionally hackathon-grade and optimized for
 *       easy indexing rather than gas efficiency.
 */
contract WillRegistry {
    struct TrusteeNode {
        address wallet;
        bool zkVerified;
        bool approvedByOwner;
        bool hasApproved;
        bool isActive;
        address[] backups;
        address parent;
    }

    struct WillData {
        address owner;
        address beneficiary;
        address vaultAddress;
        string ipfsCID;
        address[] level1;
        address[] replacementPool;
        bool isSealed;
        bool executed;
        uint256 createdAt;
    }

    // owner => will data
    mapping(address => WillData) private wills;

    // owner => linearized trustee nodes (for frontend tree reconstruction)
    mapping(address => TrusteeNode[]) private trustTrees;

    // owner => (wallet => index+1 in trustTrees[owner])
    mapping(address => mapping(address => uint256)) private trusteeIndex;

    // owner => (trustee => nullifier hash)
    mapping(address => mapping(address => uint256)) public nullifierHashes;

    event WillCreated(address indexed owner, address indexed beneficiary);
    event TrusteeAdded(address indexed owner, address trustee, address parent);
    event TrusteeApprovedByOwner(address indexed owner, address trustee);
    event WillSealed(address indexed owner);
    event ApprovalSubmitted(address indexed owner, address indexed trustee);
    event ReplacementActivated(
        address indexed owner,
        address inactive,
        address replacement
    );
    event WillExecuted(
        address indexed owner,
        address indexed beneficiary,
        string ipfsCID
    );
    event BranchAtRisk(address indexed owner, address branchRoot);

    modifier onlyWillOwner(address owner) {
        require(msg.sender == owner, "Not will owner");
        _;
    }

    modifier willExists(address owner) {
        require(wills[owner].owner != address(0), "Will does not exist");
        _;
    }

    // ---------------------------------------------------------------------
    // Core will creation & configuration
    // ---------------------------------------------------------------------

    function createWill(
        address beneficiary,
        address vaultAddress,
        string memory ipfsCID
    ) external {
        require(beneficiary != address(0), "Invalid beneficiary");
        require(vaultAddress != address(0), "Invalid vault address");
        require(
            wills[msg.sender].owner == address(0),
            "Will already exists for owner"
        );

        WillData storage w = wills[msg.sender];
        w.owner = msg.sender;
        w.beneficiary = beneficiary;
        w.vaultAddress = vaultAddress;
        w.ipfsCID = ipfsCID;
        w.createdAt = block.timestamp;

        emit WillCreated(msg.sender, beneficiary);
    }

    /**
     * Add a trustee to the trust tree.
     * - parent == address(0) => level-1 root trustee.
     * - otherwise, trustee is added as a backup under the given parent.
     */
    function addTrustee(address trustee, address parent) external {
        require(trustee != address(0), "Invalid trustee");

        WillData storage w = wills[msg.sender];
        require(w.owner != address(0), "Will not created");
        require(!w.executed, "Will already executed");

        TrusteeNode[] storage tree = trustTrees[msg.sender];

        if (parent == address(0)) {
            // Level 1 trustee
            TrusteeNode memory node = TrusteeNode({
                wallet: trustee,
                zkVerified: false,
                approvedByOwner: false,
                hasApproved: false,
                isActive: true,
                backups: new address[](0),
                parent: address(0)
            });
            tree.push(node);
            trusteeIndex[msg.sender][trustee] = tree.length; // index+1
            w.level1.push(trustee);
            emit TrusteeAdded(msg.sender, trustee, parent);
        } else {
            // Backup trustee under parent
            uint256 idx = trusteeIndex[msg.sender][parent];
            require(idx > 0, "Parent not found");

            TrusteeNode storage parentNode = tree[idx - 1];
            parentNode.backups.push(trustee);

            TrusteeNode memory node2 = TrusteeNode({
                wallet: trustee,
                zkVerified: false,
                approvedByOwner: false,
                hasApproved: false,
                isActive: true,
                backups: new address[](0),
                parent: parent
            });
            tree.push(node2);
            trusteeIndex[msg.sender][trustee] = tree.length;

            emit TrusteeAdded(msg.sender, trustee, parent);
        }
    }

    function approveTrustee(address trustee) external {
        WillData storage w = wills[msg.sender];
        require(w.owner != address(0), "Will not created");
        require(!w.executed, "Will already executed");

        uint256 idx = trusteeIndex[msg.sender][trustee];
        require(idx > 0, "Trustee not found");
        TrusteeNode storage node = trustTrees[msg.sender][idx - 1];
        node.approvedByOwner = true;

        emit TrusteeApprovedByOwner(msg.sender, trustee);
    }

    function addToReplacementPool(address member) external {
        WillData storage w = wills[msg.sender];
        require(w.owner != address(0), "Will not created");
        require(!w.executed, "Will already executed");
        require(member != address(0), "Invalid member");

        // naive: allow duplicates; frontend can de-duplicate
        w.replacementPool.push(member);
    }

    function markZKVerified(address trustee, uint256 nullifierHash) external {
        WillData storage w = wills[msg.sender];
        require(w.owner != address(0), "Will not created");
        require(!w.executed, "Will already executed");

        uint256 idx = trusteeIndex[msg.sender][trustee];
        require(idx > 0, "Trustee not found");
        TrusteeNode storage node = trustTrees[msg.sender][idx - 1];
        node.zkVerified = true;
        nullifierHashes[msg.sender][trustee] = nullifierHash;
    }

    function sealWill() external {
        WillData storage w = wills[msg.sender];
        require(w.owner != address(0), "Will not created");
        require(!w.isSealed, "Already sealed");
        require(!w.executed, "Will already executed");

        w.isSealed = true;
        emit WillSealed(msg.sender);
    }

    // ---------------------------------------------------------------------
    // Trustee approvals & replacements
    // ---------------------------------------------------------------------

    function submitApproval(address willOwner) external willExists(willOwner) {
        WillData storage w = wills[willOwner];
        require(!w.executed, "Will already executed");
        require(w.isSealed, "Will not sealed");

        uint256 idx = trusteeIndex[willOwner][msg.sender];
        require(idx > 0, "Not a trustee");

        TrusteeNode storage node = trustTrees[willOwner][idx - 1];
        require(node.isActive, "Inactive trustee");
        node.hasApproved = true;

        emit ApprovalSubmitted(willOwner, msg.sender);
    }

    function activateReplacement(
        address willOwner,
        address inactive,
        address replacement
    ) external onlyWillOwner(willOwner) willExists(willOwner) {
        WillData storage w = wills[willOwner];
        require(!w.executed, "Will already executed");

        uint256 inactiveIdx = trusteeIndex[willOwner][inactive];
        uint256 replacementIdx = trusteeIndex[willOwner][replacement];
        require(inactiveIdx > 0, "Inactive trustee not found");
        require(replacementIdx > 0, "Replacement not found");

        TrusteeNode storage inactiveNode = trustTrees[willOwner][
            inactiveIdx - 1
        ];
        TrusteeNode storage replacementNode = trustTrees[willOwner][
            replacementIdx - 1
        ];

        inactiveNode.isActive = false;
        replacementNode.isActive = true;

        emit ReplacementActivated(willOwner, inactive, replacement);
    }

    function checkFullConsensus(
        address willOwner
    ) public view willExists(willOwner) returns (bool) {
        WillData storage w = wills[willOwner];
        if (!w.isSealed || w.executed) {
            return false;
        }

        TrusteeNode[] storage tree = trustTrees[willOwner];
        for (uint256 i = 0; i < tree.length; i++) {
            if (!tree[i].isActive) continue;
            if (
                !tree[i].zkVerified ||
                !tree[i].approvedByOwner ||
                !tree[i].hasApproved
            ) {
                return false;
            }
        }
        return true;
    }

    // ---------------------------------------------------------------------
    // Execution
    // ---------------------------------------------------------------------

    function executeWill(
        address willOwner
    ) external willExists(willOwner) onlyWillOwner(willOwner) {
        WillData storage w = wills[willOwner];
        require(w.isSealed, "Will not sealed");
        require(!w.executed, "Already executed");
        require(checkFullConsensus(willOwner), "Consensus not reached");
        require(w.vaultAddress != address(0), "No vault linked");

        w.executed = true;

        // Trigger underlying NexusVault inheritance
        INexusVault(w.vaultAddress).executeInheritance();

        emit WillExecuted(willOwner, w.beneficiary, w.ipfsCID);
    }

    // ---------------------------------------------------------------------
    // Views
    // ---------------------------------------------------------------------

    function getTrustTree(
        address willOwner
    ) external view returns (TrusteeNode[] memory) {
        return trustTrees[willOwner];
    }

    function getWillStatus(
        address willOwner
    ) external view returns (WillData memory) {
        return wills[willOwner];
    }
}

